// Created: 2026-04-22
// Updated: 2026-04-26 (M119 #1475 + #1479 + #1480)

/**
 * Context-Crossing Warn — Issue #1470 (extended by M119 dogfood cluster)
 *
 * Hosted on PostToolUse so it catches the actual pain point: "a subagent/tool
 * just returned a large output and now context has quietly ballooned over the
 * threshold without me noticing."
 *
 * **Phase-aware zones (#1480)** — three behavioral zones by % of active context:
 *   0–70%   Productive    silent
 *   70–85%  Wind-down     one-shot soft notice
 *   85%+    Imminent      one-shot hard notice + gates pre-compact prompt
 *
 * **Window scaling (#1475)** — defaults are computed as % of the active
 * `CLAUDE_MAX_CONTEXT` window, not as static token counts. A 150k constant
 * fires at 75% of a 200k window (too late) and at 15% of a 1M window
 * (premature during healthy work). Anchoring at CC's auto-compact point (~85%)
 * keeps the nudge near the actual decision moment regardless of window size.
 *
 * **Cache-aware messaging (#1479)** — at 1M context, prompt cache value can
 * be substantial. /clear nukes cache; /compact preserves continuity. When the
 * session has accumulated >50k cache-read tokens, the message recommends
 * /compact instead of presenting both as equal siblings.
 *
 * Config:
 *   ORK_NO_CTX_WARN=1                — fully disable
 *   ORK_CTX_WARN_THRESHOLD=N         — back-compat: use raw N as imminent
 *                                      threshold; suppresses wind-down zone
 *   ORK_CTX_WINDDOWN_PCT=0.70        — wind-down zone start (fraction of window)
 *   ORK_CTX_IMMINENT_PCT=0.85        — imminent zone start (fraction of window)
 *   ORK_CACHE_HOT_THRESHOLD=50000    — cache-read tokens that flip messaging
 *   ORK_NO_CACHE_AWARENESS=1         — force neutral messaging
 *   CLAUDE_MAX_CONTEXT=N             — active context window in tokens
 */

import { mkdirSync, appendFileSync } from 'node:fs';
import { join, dirname } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import {
  outputSilentSuccess,
  outputWithContext,
  getProjectDir,
  getSessionId,
} from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';
import {
  estimateTokens,
  detectContentKind,
  extractToolOutputText,
  type ContentKind,
} from '../lib/token-estimator.js';
import { getContextWindowTokens } from '../lib/context-window.js';
import {
  loadAccumState,
  saveAccumState,
  evaluateCacheHeat,
  type AccumState,
} from '../lib/session-token-accum.js';

const HOOK_NAME = 'posttool/context-crossing-warn';

const DEFAULT_WINDDOWN_PCT = 0.70;
const DEFAULT_IMMINENT_PCT = 0.85;

interface EstimateResult {
  tokens: number;
  kind: ContentKind;
}

function estimateAddedTokens(input: HookInput): EstimateResult {
  const text = extractToolOutputText(input);
  if (!text) return { tokens: 0, kind: 'unknown' };
  const kind = detectContentKind(input.tool_name, text);
  const tokens = estimateTokens(text, kind);
  return { tokens, kind };
}

function logImageEvent(projectDir: string, toolName: string | undefined, charLen: number): void {
  try {
    const logPath = join(projectDir, '.claude', 'telemetry', 'image-responses.jsonl');
    mkdirSync(dirname(logPath), { recursive: true });
    appendFileSync(
      logPath,
      `${JSON.stringify({
        timestamp: new Date().toISOString(),
        tool: toolName ?? 'unknown',
        char_len: charLen,
      })}\n`,
    );
  } catch {
    // telemetry is best-effort
  }
}

function readPctEnv(name: string, fallback: number): number {
  const raw = process.env[name];
  if (!raw) return fallback;
  const parsed = parseFloat(raw);
  if (!Number.isFinite(parsed) || parsed <= 0 || parsed >= 1) return fallback;
  return parsed;
}

interface ZoneThresholds {
  windDown: number | null; // null when wind-down zone disabled
  imminent: number;
  windDownKey: string | null;
  imminentKey: string;
  windowTokens: number;
  /** True when ORK_CTX_WARN_THRESHOLD is set — wind-down disabled for back-compat. */
  rawOverride: boolean;
}

function computeZones(): ZoneThresholds {
  const windowTokens = getContextWindowTokens();
  const rawOverride = process.env.ORK_CTX_WARN_THRESHOLD;
  if (rawOverride) {
    const parsed = parseInt(rawOverride, 10);
    if (Number.isFinite(parsed) && parsed > 0) {
      return {
        windDown: null,
        imminent: parsed,
        windDownKey: null,
        imminentKey: String(parsed),
        windowTokens,
        rawOverride: true,
      };
    }
  }
  const windDownPct = readPctEnv('ORK_CTX_WINDDOWN_PCT', DEFAULT_WINDDOWN_PCT);
  const imminentPct = readPctEnv('ORK_CTX_IMMINENT_PCT', DEFAULT_IMMINENT_PCT);
  const windDown = Math.round(windowTokens * windDownPct);
  const imminent = Math.round(windowTokens * imminentPct);
  return {
    windDown,
    imminent,
    windDownKey: `windDown:${windDown}`,
    imminentKey: `imminent:${imminent}`,
    windowTokens,
    rawOverride: false,
  };
}

function formatNumber(n: number): string {
  return n.toLocaleString('en-US');
}

function pctOfWindow(tokens: number, windowTokens: number): number {
  return Math.round((tokens / windowTokens) * 100);
}

function buildMessage(
  zone: 'windDown' | 'imminent',
  state: AccumState,
  zones: ZoneThresholds,
): string {
  const used = state.estimatedTokens;
  const usedPct = pctOfWindow(used, zones.windowTokens);
  const cacheHeat = evaluateCacheHeat(state);

  if (zone === 'windDown') {
    return (
      `[context] Approaching compact zone — est. ${formatNumber(used)} tokens (~${usedPct}% of window). ` +
      `Natural breakpoint soon? /clear for a fresh task, /compact to keep history.`
    );
  }

  // imminent zone
  if (cacheHeat === 'hot' && !zones.rawOverride) {
    const cacheReads = formatNumber(state.cacheReadTokens);
    return (
      `[context] Session crossed ~${usedPct}% of window (est. ${formatNumber(used)} tokens, ` +
      `${cacheReads} cache-read accumulated). Consider /compact — keeps your warm cache. ` +
      `/clear only if switching projects.`
    );
  }
  return (
    `[context] Session context crossed ~${formatNumber(zones.imminent)} tokens ` +
    `(est. ${formatNumber(used)}, ~${usedPct}% of window). ` +
    `/clear to start a fresh task with zero context cost, ` +
    `/compact to keep history and continue.`
  );
}

export function contextCrossingWarn(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  if (process.env.ORK_NO_CTX_WARN === '1') {
    return outputSilentSuccess();
  }

  try {
    const projectDir = ctx.projectDir || getProjectDir();
    const sessionId = ctx.sessionId || getSessionId();
    const state = loadAccumState(projectDir, sessionId);
    const zones = computeZones();

    const { tokens: added, kind } = estimateAddedTokens(input);
    state.estimatedTokens += added;
    state.updatedAt = new Date().toISOString();
    if (input.tool_name) state.lastToolName = input.tool_name;

    state.kindCounts = state.kindCounts ?? {};
    state.kindCounts[kind] = (state.kindCounts[kind] ?? 0) + 1;

    if (kind === 'image') {
      state.imageResponses = (state.imageResponses ?? 0) + 1;
      const sampleText = extractToolOutputText(input);
      logImageEvent(projectDir, input.tool_name, sampleText.length);
    }

    // Decide which zone (if any) just crossed. Imminent wins over wind-down
    // when both cross in the same call (e.g. very large single tool result).
    let firedZone: 'windDown' | 'imminent' | null = null;
    let firedKey: string | null = null;

    if (
      state.estimatedTokens >= zones.imminent &&
      state.crossings[zones.imminentKey] !== true
    ) {
      firedZone = 'imminent';
      firedKey = zones.imminentKey;
    } else if (
      zones.windDown !== null &&
      zones.windDownKey !== null &&
      state.estimatedTokens >= zones.windDown &&
      state.crossings[zones.windDownKey] !== true
    ) {
      firedZone = 'windDown';
      firedKey = zones.windDownKey;
    }

    if (firedZone && firedKey) {
      state.crossings = { ...(state.crossings ?? {}), [firedKey]: true };
      // When wind-down fires first and imminent later, also mark wind-down as
      // crossed when we fire imminent — prevents a backward soft notice.
      if (firedZone === 'imminent' && zones.windDownKey) {
        state.crossings[zones.windDownKey] = true;
      }
    }

    saveAccumState(projectDir, sessionId, state);

    if (firedZone) {
      const msg = buildMessage(firedZone, state, zones);
      ctx.log(
        HOOK_NAME,
        `${firedZone} fired at ${state.estimatedTokens} tokens ` +
          `(threshold ${firedZone === 'imminent' ? zones.imminent : zones.windDown})`,
      );
      return outputWithContext(msg);
    }

    return outputSilentSuccess();
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    ctx.log(HOOK_NAME, `failed: ${msg}`, 'warn');
    return outputSilentSuccess();
  }
}

export default contextCrossingWarn;
